(function(){
  try {
    var result = {};
    var bodyText = document.body.innerText;
    var m1 = bodyText.match(/第\s*(\d+)\s*天/);
    result.day = m1 ? parseInt(m1[1]) : null;
    var m2 = bodyText.match(/春季|夏季|秋季|冬季/);
    result.season = m2 ? m2[0] : null;
    var m3 = bodyText.match(/💰\s*([\d,]+)/);
    result.money = m3 ? parseInt(m3[1].replace(/,/g,'')) : null;
    var m4 = bodyText.match(/⚡\s*([\d]+)\s*\/\s*([\d]+)/);
    result.stamina = m4 ? parseInt(m4[1]) : null;
    result.maxStamina = m4 ? parseInt(m4[2]) : null;
    var m5 = bodyText.match(/❤️\s*([\d]+)\s*\/\s*([\d]+)/);
    result.health = m5 ? parseInt(m5[1]) : null;
    result.maxHealth = m5 ? parseInt(m5[2]) : null;
    var m6 = bodyText.match(/水稻[：:]\s*([\d,]+)/);
    result.rice = m6 ? parseInt(m6[1].replace(/,/g,'')) : null;
    var m7 = bodyText.match(/红薯[：:]\s*([\d,]+)/);
    result.sweet = m7 ? parseInt(m7[1].replace(/,/g,'')) : null;
    var m8 = bodyText.match(/([^\s]+雨|晴|阴|多云|雪|雾)/);
    result.weather = m8 ? m8[1] : null;
    result.time = null;
    var timeEl = document.querySelector('[id*=time],.time-display');
    if (timeEl) result.time = timeEl.textContent.trim();
    var fields = [];
    var fieldHeaders = document.querySelectorAll('h3, h4, .field-title');
    fieldHeaders.forEach(function(h){
      var txt = h.textContent;
      if (txt.match(/第[一二三四五六七八九十\d]+块田/)) {
        var parent = h.closest('.field-card, .field-item, div, section');
        var status = parent ? parent.textContent : '';
        var stage = 'idle';
        if (status.match(/成熟|mature/)) stage = 'mature';
        else if (status.match(/生长|growing/)) stage = 'growing';
        else if (status.match(/移栽|transplanting/)) stage = 'transplanting';
        else if (status.match(/育苗|seedling/)) stage = 'seedling';
        else if (status.match(/播种|sowed/)) stage = 'sowed';
        var cropMatch = status.match(/水稻|rice|红薯|sweet/);
        var crop = cropMatch ? cropMatch[0] : null;
        var progMatch = status.match(/([\d]+)%/);
        var progress = progMatch ? parseInt(progMatch[1]) : 0;
        fields.push({stage: stage, crop: crop, progress: progress});
      }
    });
    result.fieldsCount = fields.length;
    result.fields = fields;
    var npcs = {};
    var npcEls = document.querySelectorAll('[class*=npc],[class*=friend]');
    npcEls.forEach(function(el){
      var txt = el.textContent;
      var nameMatch = txt.match(/([^\s]{2,4})\s*(好感|friend)/);
      if (nameMatch) {
        var valMatch = txt.match(/([\d]+)/);
        npcs[nameMatch[1]] = valMatch ? parseInt(valMatch[1]) : 0;
      }
    });
    result.npcs = npcs;
    var skills = {};
    var skillEls = document.querySelectorAll('[class*=skill]');
    skillEls.forEach(function(el){
      var txt = el.textContent;
      var nameMatch = txt.match(/([^\s]{2,6})\s*([\d]+)级/);
      if (nameMatch) {
        skills[nameMatch[1]] = parseInt(nameMatch[2]);
      }
    });
    result.skills = skills;
    return JSON.stringify(result);
  } catch(e) {
    return JSON.stringify({error: e.message});
  }
})()
